#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to find the sum of deepest leaves
int deepestLeavesSum(Node* root) {
    if (root == NULL) return 0;

    int maxLevel = 0;
    int sum = 0;

    // Create a queue for BFS and enqueue the root node
    Node** queue = (Node**) malloc(sizeof(Node*) * 10000);
    int* level = (int*) malloc(sizeof(int) * 10000);
    int front = 0, rear = 0;
    queue[rear] = root;
    level[rear] = 0;
    rear++;

    while (front < rear) {
        Node* temp = queue[front];
        int currLevel = level[front];
        front++;

        if (currLevel > maxLevel) {
            maxLevel = currLevel;
            sum = temp->val;
        } else if (currLevel == maxLevel) {
            sum += temp->val;
        }

        if (temp->left) {
            queue[rear] = temp->left;
            level[rear] = currLevel + 1;
            rear++;
        }

        if (temp->right) {
            queue[rear] = temp->right;
            level[rear] = currLevel + 1;
            rear++;
        }
    }

    free(queue);
    free(level);
    return sum;
}

int main() {
    int N;
    scanf("%d", &N);

    Node* root = NULL;
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
