            root = createNode(pi);
            parentNode = root;
        } else {
            parentNode = root;
            while (parentNode->val != pi) {
                if (parentNode->left && parentNode->left->val == pi) {
                    parentNode = parentNode->left;
                    break;
                }
                if (parentNode->right && parentNode->right->val == pi) {
                    parentNode = parentNode->right;
                    break;
                }
                if (parentNode->left) parentNode = parentNode->left;
            }
        }

