import java.util.Queue;
import java.util.LinkedList;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int val;
        Node left;
        Node right;

        Node(int val) {
            this.val = val;
            this.left = null;
            this.right = null;
        }
    }

    // Function to find the sum of deepest leaves
    public static int deepestLeavesSum(Node root) {
        if (root == null) return 0;

        int maxLevel = 0;
        int sum = 0;

        // Create a queue for BFS and enqueue the root node
        Queue<Node> q = new LinkedList<>();
        Queue<Integer> level = new LinkedList<>();
        q.add(root);
        level.add(0);

        while (!q.isEmpty()) {
            Node temp = q.poll();
            int currLevel = level.poll();

            if (currLevel > maxLevel) {
                maxLevel = currLevel;
                sum = temp.val;
            } else if (currLevel == maxLevel) {
                sum += temp.val;
            }

            if (temp.left != null) {
                q.add(temp.left);
                level.add(currLevel + 1);
            }

            if (temp.right != null) {
                q.add(temp.right);
                level.add(currLevel + 1);
            }
        }

        return sum;
    }

    public static void main(String[] args) {
        // Read input
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int N = sc.nextInt();
        sc.nextLine();

        Node root = null;
        for (int i = 0; i < N - 1; i++) {
            String[] input = sc.nextLine().split(" ");
            int pi = Integer.parseInt(input[0]);
            int ci = Integer.parseInt(input[1]);
            char Ri = input[2].charAt(0);

            // Create nodes if they don't exist
            Node parentNode = null;
            Node childNode = null;
            if (root == null) {
                root = new Node(pi);
                parentNode = root;
            } else {
                parentNode = root;
                while (parentNode.val != pi) {
                    if (parentNode.left != null && parentNode.left.val == pi) {
                        parentNode = parentNode.left;
                        break;
                    }
                    if (parentNode.right != null && parentNode.right.val == pi) {
                        parentNode = parentNode.right;
                        break;
                    }
                    if (parentNode.left != null) parentNode = parentNode.left;
                }
            }

            if (Ri == 'L') {
                if (parentNode.left == null) {
                    parentNode.left = new Node(ci);
                }
            } else {
                if (parentNode.right == null) {
                    parentNode.right = new Node(ci);
                }
            }
        }

        System.out.println(deepestLeavesSum(root));
    }
